#bd93f9;\n  text-transform: uppercase;\n  letter-spacing: 0.5px;\n}\n.pipeline-section[_ngcontent-%COMP%]   .section-desc[_ngcontent-%COMP%] {\n  font-size: 0.75rem;\n  color: #a0a0b8;\n}\n\n\n\n.pipeline-flow[_ngcontent-%COMP%] {\n  display: flex;\n  flex-direction: column;\n  gap: 20px;\n  position: relative;\n  padding-left: 10px;\n}\n\n.pipeline-node[_ngcontent-%COMP%] {\n  display: flex;\n  align-items: center;\n  gap: 16px;\n  position: relative;\n  cursor: pointer;\n  -webkit-user-select: none;\n          user-select: none;\n}\n.pipeline-node[_ngcontent-%COMP%]   .node-bullet[_ngcontent-%COMP%] {\n  width: 28px;\n  height: 28px;\n  border-radius: 50%;\n  background: #120e22;\n  border: 2px solid rgba(189, 147, 249, 0.25);\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  font-size: 0.75rem;\n  font-weight: bold;\n  color: #a0a0b8;\n  z-index: 5;\n  transition: all 0.2s;\n}\n.pipeline-node[_ngcontent-%COMP%]   .node-bullet[_ngcontent-%COMP%]   span[_ngcontent-%COMP%] {\n  font-size: 16px;\n  color: #06040a;\n  font-weight: bold;\n}\n.pipeline-node[_ngcontent-%COMP%]   .node-label[_ngcontent-%COMP%] {\n  font-size: 0.85rem;\n  color: #a0a0b8;\n  font-weight: 500;\n  transition: color 0.2s;\n}\n.pipeline-node[_ngcontent-%COMP%]   .node-connector[_ngcontent-%COMP%] {\n  position: absolute;\n  top: 28px;\n  left: 13px;\n  width: 2px;\n  height: 22px;\n  background: rgba(189, 147, 249, 0.15);\n  z-index: 1;\n}\n.pipeline-node.completed[_ngcontent-%COMP%]   .node-bullet[_ngcontent-%COMP%] {\n  background: #bd93f9;\n  border-color: #bd93f9;\n  color: #06040a;\n}\n.pipeline-node.completed[_ngcontent-%COMP%]   .node-label[_ngcontent-%COMP%] {\n  color: #bd93f9;\n}\n.pipeline-node.completed[_ngcontent-%COMP%]   .node-connector[_ngcontent-%COMP%] {\n  background: #bd93f9;\n}\n.pipeline-node.active[_ngcontent-%COMP%]   .node-bullet[_ngcontent-%COMP%] {\n  background: #00e5ff;\n  border-color: #00e5ff;\n  color: #06040a;\n  box-shadow: 0 0 10px rgba(